// Unit 4: Test Planning (Chapter 5, pp.79–92)
EXTRA_UNITS.push({
id:4, concepts:[
{title:"🎯 Learning Objectives",ref:"Module 4",content:`<p>By the end of this chapter you should be able to:</p><ul><li>Connect the <strong>test strategy</strong> (from Unit 3 chessboard) to <strong>test plan</strong> development</li><li>Connect a <strong>test plan</strong> to <strong>test case</strong> writing and execution</li><li>Synchronize test documentation writing with the <strong>development phases</strong></li></ul><div class="zh-note">本章目标：把"测试策略"（棋盘）→"测试计划"→"测试用例"→"执行"串联起来，让测试文档和开发阶段同步进行。</div>`},
{title:"📋 What is a Test Plan?",ref:"pp.79–80",content:`<p>A <span class="key-term">test plan</span> is the master blueprint for the entire testing effort. It answers <strong>4 questions</strong>:</p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:13.5px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:10px;text-align:left;color:var(--accent-dim);width:80px;">Question</th><th style="padding:10px;text-align:left;color:var(--accent-dim);">Means</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:8px 10px;font-weight:700;color:var(--blue);">❓ WHAT</td><td style="padding:8px 10px;">Which apps / systems / features to test (scope &amp; objectives)</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:8px 10px;font-weight:700;color:var(--purple);">🛠️ HOW</td><td style="padding:8px 10px;">Which testing approaches to use (the chess board strategy)</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:8px 10px;font-weight:700;color:var(--orange);">📅 WHEN</td><td style="padding:8px 10px;">Schedule across development phases — when each test runs</td></tr><tr style="background:var(--bg-warm);"><td style="padding:8px 10px;font-weight:700;color:var(--green);">👥 WHO</td><td style="padding:8px 10px;">Roles &amp; expertise needed (testers, devs, business experts)</td></tr></tbody></table><div class="callout important"><strong>⚠️ Common Mistake:</strong> Jumping from strategy directly to test cases — like a developer jumping from design to coding. The test plan is the <em>critical intermediate step</em>.</div><div class="zh-note">测试计划 = 总蓝图，回答 4 个问题：WHAT(测什么) + HOW(怎么测) + WHEN(何时测) + WHO(谁来测)。从"策略"到"用例"之间不能跳过！</div>`},
{title:"📑 10 Test Plan Items + LMS Example",ref:"pp.80–83",content:`<p>Every test plan should contain these 10 items. Below: each item with a real <strong>Library Management System (LMS)</strong> example.</p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:12.5px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);width:30px;">#</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Item</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">LMS Example</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--accent);">1</td><td style="padding:6px 8px;"><strong>Systems to be tested</strong></td><td style="padding:6px 8px;font-style:italic;">Library Management System (LMS) — book issue/return module</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--accent);">2</td><td style="padding:6px 8px;"><strong>Testing objectives</strong> + rationale</td><td style="padding:6px 8px;font-style:italic;">Ensure book issue/return works correctly (high business risk: lost books)</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--accent);">3</td><td style="padding:6px 8px;"><strong>Scope &amp; limitations</strong></td><td style="padding:6px 8px;font-style:italic;">✅ Book management · ❌ External payment gateway (out of scope)</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--accent);">4</td><td style="padding:6px 8px;"><strong>Business expertise</strong> sources</td><td style="padding:6px 8px;font-style:italic;">Librarian validates borrowing rules &amp; late-fee policy</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--accent);">5</td><td style="padding:6px 8px;"><strong>Development expertise</strong> sources</td><td style="padding:6px 8px;font-style:italic;">Developer explains database relationships + schema</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--accent);">6</td><td style="padding:6px 8px;"><strong>Test data sources</strong></td><td style="padding:6px 8px;font-style:italic;">Sample student records + book inventory DB</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--accent);">7</td><td style="padding:6px 8px;"><strong>Test environment</strong></td><td style="padding:6px 8px;font-style:italic;">Same web server, DB, browser as production</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--accent);">8</td><td style="padding:6px 8px;"><strong>Testing strategy</strong> (chess board)</td><td style="padding:6px 8px;font-style:italic;">Static + functional + integration + security + performance</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--accent);">9</td><td style="padding:6px 8px;"><strong>&lt;Repeated&gt;</strong> phase-wise details</td><td style="padding:6px 8px;font-style:italic;">Each phase: requirements/design/code/test → repeat 7 sub-items (see next card)</td></tr><tr style="background:var(--bg-warm);"><td style="padding:6px 8px;font-weight:700;color:var(--accent);">10</td><td style="padding:6px 8px;"><strong>Overall testing schedule</strong></td><td style="padding:6px 8px;font-style:italic;">Master plan: dates for all phase activities combined</td></tr></tbody></table><div class="callout">👉 Try the <strong>Interactive tab → Test Plan Explorer</strong> to click each item and see expanded examples.</div><div class="zh-note">10 大项 = 测试计划骨架。LMS（图书系统）例子贯穿全部 10 项，每一项都有具体示例。</div>`},
{title:"🔁 Item #9: Phase-Wise Repeated Details",ref:"pp.81–83",content:`<p>Item #9 is the BIG one. It <strong>repeats for every development phase</strong> (requirements, design, coding, etc.). Each repetition has 7 sub-items:</p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:13px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:8px;text-align:left;color:var(--accent-dim);width:40px;">9.x</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">Sub-item</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">Example (LMS)</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--purple);">a</td><td style="padding:6px 8px;">Development phase name</td><td style="padding:6px 8px;font-style:italic;">"Requirements" / "Design" / "Coding"</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--purple);">b</td><td style="padding:6px 8px;"><strong>Start criteria</strong> — when can we begin testing?</td><td style="padding:6px 8px;font-style:italic;">LMS modules developed + deployed to test env</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--purple);">c</td><td style="padding:6px 8px;"><strong>End criteria</strong> — when are we done?</td><td style="padding:6px 8px;font-style:italic;">All critical defects fixed + retested</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--purple);">d</td><td style="padding:6px 8px;">&lt;Draft&gt; test case <strong>list</strong> (IDs + titles)</td><td style="padding:6px 8px;font-style:italic;">TC-001 book search, TC-002 issue, TC-003 return</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--purple);">e</td><td style="padding:6px 8px;">&lt;Draft&gt; test case <strong>writing</strong> schedule</td><td style="padding:6px 8px;font-style:italic;">Week 1 — prepare test cases</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--purple);">f</td><td style="padding:6px 8px;">&lt;Draft&gt; test case <strong>execution</strong> schedule</td><td style="padding:6px 8px;font-style:italic;">Week 2 — execute functional tests</td></tr><tr><td style="padding:6px 8px;font-weight:700;color:var(--purple);">g</td><td style="padding:6px 8px;">&lt;Draft&gt; results <strong>analysis + reporting</strong> schedule</td><td style="padding:6px 8px;font-style:italic;">Week 3 — defect analysis + reporting</td></tr></tbody></table><div class="callout important"><strong>The word "&lt;Draft&gt;"</strong> is key — these schedules will shift as the project progresses. Test plans are LIVING documents, updated each phase. Expect 3–4 weeks of extra time by the ⅓ mark.</div><div class="zh-note">第 9 项要为每个开发阶段重复一遍 7 个子项 (a-g)。带 &lt;Draft&gt; 标记的内容会随项目进展不断更新——计划是活的，不是定的。</div>`},
{title:"✍️ Test Case Creation: Risk → Detailed Steps",ref:"pp.83",content:`<p>Test cases start <strong>high-level</strong>, then get <strong>detailed</strong> as development progresses. The 3-input → 1-output formula:</p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:13px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:8px;text-align:left;color:var(--accent-dim);">📥 Input (from where)</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">Example</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:8px;color:var(--blue);font-weight:600;">📋 Business Requirements</td><td style="padding:8px;font-style:italic;">"User can login"</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:8px;color:var(--orange);font-weight:600;">⚠️ Business Risks</td><td style="padding:8px;font-style:italic;">"Wrong login blocks legitimate users"</td></tr><tr><td style="padding:8px;color:var(--purple);font-weight:600;">📜 Software Specifications</td><td style="padding:8px;font-style:italic;">"Password ≥ 8 characters"</td></tr></tbody></table><p style="text-align:center;margin:10px 0;font-size:18px;color:var(--accent);">⬇️</p><div style="background:var(--bg-warm);padding:14px 18px;border-radius:10px;border-left:3px solid var(--green);font-size:13.5px;"><strong>📐 Step-by-Step Test Case:</strong><br>Enter username → enter password → click login → verify success/error message</div><p><strong>🎓 College Registration Example:</strong></p><div style="background:var(--bg-warm);padding:12px 16px;border-radius:8px;margin:8px 0;font-size:13px;">Test team manager says: <em>"At this phase, we need to test all data entry screens."</em><br><br>Team identifies all input forms requiring test cases:<br>• 📝 Registration form &nbsp; • 🔐 Login form &nbsp; • 📍 Address entry &nbsp; • 💳 Payment details</div><div class="callout">"All data entry screens" = every user input form that needs <strong>accuracy + validation</strong> testing.</div><div class="zh-note">测试用例 = 需求 + 风险 + 规范 → 具体步骤。初期粗糙，随开发细化。校园注册例子：先识别所有数据录入界面，再为每个写用例。</div>`},
{title:"📐 The 15-Item Test Case Anatomy",ref:"pp.83–88",content:`<p>Every test case contains 15 standard items. Items 1–4 come from the test plan; 12–15 are <strong>&lt;Placeholders&gt;</strong> filled in AFTER execution.</p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:12px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:6px;text-align:left;color:var(--accent-dim);width:50px;">Group</th><th style="padding:6px;text-align:left;color:var(--accent-dim);">Items</th><th style="padding:6px;text-align:left;color:var(--accent-dim);">Content</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px;font-weight:700;color:var(--blue);">📋 Identity</td><td style="padding:6px;">1–4</td><td style="padding:6px;">ID · Title · Description · Development phase <em>(from test plan)</em></td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px;font-weight:700;color:var(--purple);">🎯 Setup</td><td style="padding:6px;">5–7</td><td style="padding:6px;">Testing goals + measures · Suggested test data · Suggested test tools</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px;font-weight:700;color:var(--orange);">⚙️ Procedure</td><td style="padding:6px;">8–11</td><td style="padding:6px;">Startup procedure · Closedown · Reset/rerun procedure</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px;font-weight:700;color:var(--green);">🔁 Execution</td><td style="padding:6px;">12</td><td style="padding:6px;"><strong>Repeated steps:</strong> # → action → expected → &lt;actual&gt;</td></tr><tr><td style="padding:6px;font-weight:700;color:var(--red);">📝 Tracking</td><td style="padding:6px;">13–15</td><td style="padding:6px;"><strong>&lt;Placeholders&gt;</strong> filled after execution: first-run date · # attempts · defects discovered · success y/n</td></tr></tbody></table><div class="callout important"><strong>Critical:</strong> &lt;Placeholder&gt; items aren't written upfront — they're filled in DURING/AFTER execution. They prove the test ran and what happened.</div><div class="zh-note">15 项测试用例分 5 组：身份(1-4) · 准备(5-7) · 流程(8-11) · 执行步骤(12) · 跟踪占位符(13-15 执行后才填)。占位符证明用例真跑过。</div>`},
{title:"⚠️ Step Actions: Avoid Screen-Dependent Steps",ref:"pp.84",content:`<p>Test steps move the cursor, enter data, click buttons. <strong>Trap:</strong> writing tests that depend on exact screen layout = brittle, fails for the wrong reasons.</p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:13px;"><thead><tr><th style="padding:10px;text-align:left;background:var(--red-bg);color:var(--red);font-weight:700;border-bottom:2px solid var(--red);">❌ Screen-Dependent (Fragile)</th><th style="padding:10px;text-align:left;background:var(--green-bg);color:var(--green);font-weight:700;border-bottom:2px solid var(--green);">✅ Layout-Independent (Stable)</th></tr></thead><tbody><tr><td style="padding:10px;vertical-align:top;background:rgba(252,232,231,0.4);">"Click at coordinates (450, 320)"<br><br>"The Submit button is blue"<br><br>"Username field is 2nd from top"</td><td style="padding:10px;vertical-align:top;background:rgba(228,242,234,0.4);">"Click the element with id='submit-btn'"<br><br>"Locate by accessible name 'Submit'"<br><br>"Find input with data-testid='username'"</td></tr></tbody></table><p><strong>Why this matters:</strong></p><ul><li>📱 Different monitors / resolutions distort layout</li><li>🎨 UI elements may shift, change labels, fonts, colors</li><li>🤖 Automated tools are precise — they treat <strong>visual changes as failures</strong>, even cosmetic ones</li><li>🔁 You don't want to rewrite 200 tests because the designer moved a button</li></ul><div class="callout important"><strong>Rule:</strong> Avoid absolute screen positions UNLESS you're explicitly testing layout. Identify elements by stable attributes (id, data-testid, role).</div><div class="zh-note">测试步骤别依赖屏幕位置！按坐标点击 = 一改 UI 全部失败。用元素 ID/属性定位才稳定。</div>`},
{title:"⚖️ Expected vs Actual + 3 Causes of Failure",ref:"pp.88–89",content:`<p>Every test step compares <span class="key-term">expected results</span> vs. <span class="key-term">actual results</span>.</p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:13.5px;"><thead><tr><th style="padding:10px;text-align:left;background:var(--green-bg);color:var(--green);font-weight:700;border-bottom:2px solid var(--green);">✅ Match</th><th style="padding:10px;text-align:left;background:var(--red-bg);color:var(--red);font-weight:700;border-bottom:2px solid var(--red);">❌ Mismatch</th></tr></thead><tbody><tr><td style="padding:10px;">Step <strong>"passed"</strong></td><td style="padding:10px;">Step <strong>"failed"</strong> — 3 possible causes:</td></tr></tbody></table><p><strong>🔍 When a step fails, investigate 3 causes (in order):</strong></p><table style="width:100%;border-collapse:collapse;margin:10px 0;font-size:13px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);width:40px;">#</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Cause</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Fix</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--blue);">1</td><td style="padding:6px 8px;"><strong>Faulty test design</strong></td><td style="padding:6px 8px;">Tester error — fix the test case</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--orange);">2</td><td style="padding:6px 8px;"><strong>Ambiguous requirements</strong></td><td style="padding:6px 8px;">Requirements bug — clarify with stakeholders</td></tr><tr><td style="padding:6px 8px;font-weight:700;color:var(--red);">3</td><td style="padding:6px 8px;"><strong>Genuine software defect</strong></td><td style="padding:6px 8px;">Code bug — log it, dev fixes</td></tr></tbody></table><div class="callout important"><strong>Investigation order matters!</strong> Always check #1 (your own test) first, then #2 (the spec), THEN file a bug for #3. Otherwise you waste developers' time chasing "bugs" that are really your typos.</div><div class="zh-note">期望 vs 实际不匹配 = 失败。3 大原因按顺序排查：① 测试自身错 ② 需求不清 ③ 真实代码 bug。先怀疑自己再怪开发者。</div>`},
{title:"🛁 The Bathtub Diagram: Plan Early, Execute Late",ref:"pp.88–90",content:`<p>Test planning + writing happens <strong>EARLY</strong> (during analysis/design). Test execution happens <strong>LATE</strong> (after coding). Plot it as activity vs time, and it looks like a bathtub.</p><div style="background:linear-gradient(180deg, var(--bg-warm), var(--surface));padding:16px 18px;border-radius:10px;margin:14px 0;border:1px solid var(--border-light);"><div style="font-size:12px;color:var(--text-dim);margin-bottom:12px;font-weight:700;text-transform:uppercase;letter-spacing:1px;">📊 Testing Activity Over SDLC Phases</div><div style="display:grid;grid-template-columns:repeat(4,1fr);gap:4px;align-items:end;height:120px;margin-bottom:8px;"><div style="background:linear-gradient(180deg,var(--blue),var(--blue-bg));height:80%;border-radius:6px 6px 0 0;display:flex;align-items:start;justify-content:center;color:#fff;font-size:10px;font-weight:700;padding:4px;">📝 PLAN</div><div style="background:linear-gradient(180deg,var(--purple),var(--purple-bg));height:55%;border-radius:6px 6px 0 0;display:flex;align-items:start;justify-content:center;color:#fff;font-size:10px;font-weight:700;padding:4px;">✍️ WRITE CASES</div><div style="background:linear-gradient(180deg,var(--orange),var(--orange-bg));height:30%;border-radius:6px 6px 0 0;display:flex;align-items:start;justify-content:center;color:#fff;font-size:10px;font-weight:700;padding:4px;">🔄 REFINE</div><div style="background:linear-gradient(180deg,var(--red),var(--red-bg));height:95%;border-radius:6px 6px 0 0;display:flex;align-items:start;justify-content:center;color:#fff;font-size:10px;font-weight:700;padding:4px;">🚀 EXECUTE</div></div><div style="display:grid;grid-template-columns:repeat(4,1fr);gap:4px;font-size:10.5px;color:var(--text-dim);text-align:center;">Analysis &nbsp;|&nbsp; Design &nbsp;|&nbsp; Coding &nbsp;|&nbsp; Final + Deploy</div></div><p><strong>🛒 E-commerce Checkout Example:</strong></p><table style="width:100%;border-collapse:collapse;margin:10px 0;font-size:12.5px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Phase</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Dev Work</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Test Activity</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;">Analysis</td><td style="padding:6px 8px;">Define checkout process</td><td style="padding:6px 8px;font-style:italic;">📝 Write test plan + draft cases</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;">Design</td><td style="padding:6px 8px;">Design payment flow</td><td style="padding:6px 8px;font-style:italic;">✍️ Write test cases (success/failure)</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;">Coding</td><td style="padding:6px 8px;">Implement payment</td><td style="padding:6px 8px;font-style:italic;">🔄 Refine cases · 🚀 Execute functional+integration tests</td></tr><tr style="background:var(--bg-warm);"><td style="padding:6px 8px;">Deployment</td><td style="padding:6px 8px;">App goes live</td><td style="padding:6px 8px;font-style:italic;">🚀 Execute UAT + performance tests</td></tr></tbody></table><div class="callout">👉 See the <strong>Interactive tab → Bathtub Animator</strong> for an animated version of this curve.</div><div class="zh-note">浴缸图：测试规划早做(高峰)，执行晚做(高峰)，中间是过渡。一图说明"测试不是开发完后才做的事"。</div>`},
{title:"🚦 4 Test Environments + Entry/Exit/Suspension Criteria + Estimation",ref:"SRS Template",content:`<p>Real-world plans extend Item #9's "phase details" with formal <strong>gates</strong> and <strong>resource math</strong>. These are crucial for industry/exam — they don't appear in the textbook but are in your course's SRS template.</p><p><strong>🌐 1. The 4 Test Environments</strong></p><table style="width:100%;border-collapse:collapse;margin:10px 0;font-size:12.5px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Environment</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Used For</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;color:var(--blue);font-weight:600;">💻 Development</td><td style="padding:6px 8px;">Unit testing + module-level debugging during coding</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;color:var(--purple);font-weight:600;">🧪 QA / Test</td><td style="padding:6px 8px;">Functional + integration + regression testing</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;color:var(--orange);font-weight:600;">🎭 Staging</td><td style="padding:6px 8px;">UAT + performance testing — last stop before prod</td></tr><tr style="background:var(--bg-warm);"><td style="padding:6px 8px;color:var(--red);font-weight:600;">🚀 Production</td><td style="padding:6px 8px;">Real system with real users (monitoring only)</td></tr></tbody></table><p><strong>🚦 2. Entry / Exit Criteria — formal "gates"</strong></p><table style="width:100%;border-collapse:collapse;margin:10px 0;font-size:13px;"><thead><tr><th style="padding:8px;text-align:left;background:var(--green-bg);color:var(--green);font-weight:700;border-bottom:2px solid var(--green);">✅ Entry — when CAN we start?</th><th style="padding:8px;text-align:left;background:var(--red-bg);color:var(--red);font-weight:700;border-bottom:2px solid var(--red);">🏁 Exit — when ARE we done?</th></tr></thead><tbody><tr><td style="padding:8px;vertical-align:top;">• Requirements approved<br>• Test environment available<br>• Test data ready<br>• Build deployed to QA</td><td style="padding:8px;vertical-align:top;">• All critical test cases executed<br>• No high-severity defects open<br>• Test coverage threshold met<br>• UAT approval received</td></tr></tbody></table><p><strong>⏸️ 3. Suspension / Resumption — "should we PAUSE?"</strong></p><table style="width:100%;border-collapse:collapse;margin:10px 0;font-size:13px;"><thead><tr><th style="padding:8px;text-align:left;background:var(--orange-bg);color:var(--orange);font-weight:700;border-bottom:2px solid var(--orange);">⏸️ Suspend testing if…</th><th style="padding:8px;text-align:left;background:var(--green-bg);color:var(--green);font-weight:700;border-bottom:2px solid var(--green);">▶️ Resume when…</th></tr></thead><tbody><tr><td style="padding:8px;vertical-align:top;">• System crash<br>• Critical defect blocks core feature<br>• Database failure<br>• Environment unavailable<br>• Payment service down</td><td style="padding:8px;vertical-align:top;">• Defects fixed + verified<br>• Stable build deployed<br>• Environment restored<br>• QA confirms stability</td></tr></tbody></table><p><strong>📊 4. Test Estimation Formula</strong></p><div style="background:var(--bg-warm);padding:14px 18px;border-radius:10px;margin:10px 0;font-family:'JetBrains Mono',monospace;font-size:14px;border-left:3px solid var(--accent);text-align:center;">effort = <em>testers</em> × <em>days per tester</em> &nbsp;&nbsp;⟹&nbsp;&nbsp; 2 × 5 = <strong>10 person-days</strong></div><p style="font-size:12.5px;color:var(--text-dim);margin-top:4px;">SRS example totals: 10 weeks · 50+ test cases · 5–7 team members · 2 defect-retesting cycles.</p><p><strong>⚠️ 5. Risks &amp; Contingencies</strong></p><table style="width:100%;border-collapse:collapse;margin:10px 0;font-size:12.5px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Risk</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Contingency</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;">Payment gateway failure</td><td style="padding:6px 8px;">Use mock payment service (Stripe test mode)</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;">Limited resources</td><td style="padding:6px 8px;">Prioritize tests by risk + frequency (80/20 rule)</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;">Environment unavailable</td><td style="padding:6px 8px;">Maintain backup environment</td></tr><tr style="background:var(--bg-warm);"><td style="padding:6px 8px;">Schedule slips</td><td style="padding:6px 8px;">Reduce testing scope (drop low-risk items)</td></tr></tbody></table><div class="callout">👉 See the <strong>Interactive tab → 🏗️ SRS Walkthrough</strong> for the full Student Registration System plan walkthrough.</div><div class="zh-note">5 个进阶概念：4 环境(Dev/QA/Staging/Prod) · Entry/Exit(开始和结束门槛) · Suspension/Resumption(暂停和恢复) · 估算公式(人 × 天) · 风险+应急。教材没有，但实战和考试必考。</div>`},
{title:"📚 IEEE 829 + ISO/IEC/IEEE 29119 Standards",ref:"pp.90–92",content:`<p>Software testing is a professional branch of engineering, so it has <strong>international standards</strong> for documentation.</p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:13px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:8px;text-align:left;color:var(--accent-dim);">Standard</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">Status</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">Notes</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);vertical-align:top;"><td style="padding:8px;color:var(--blue);font-weight:600;">📜 IEEE 829-1998<br><span style="font-weight:400;font-size:11px;color:var(--text-dim);">"Software Test Documentation Standard"</span></td><td style="padding:8px;">Older (1998)</td><td style="padding:8px;">8 standard test documents. Still widely taught + used in legacy contexts.</td></tr><tr style="background:var(--bg-warm);vertical-align:top;"><td style="padding:8px;color:var(--green);font-weight:600;">🌐 ISO/IEC/IEEE 29119<br><span style="font-weight:400;font-size:11px;color:var(--text-dim);">"Current Software Testing Standard"</span></td><td style="padding:8px;">Current (2013+)</td><td style="padding:8px;">Multi-part standard covering processes, documentation, techniques. Joint <strong>ISO + IEC + IEEE</strong> creation.</td></tr></tbody></table><p><strong>📊 IEEE 829 vs ISO/IEC/IEEE 29119 — what actually changed?</strong></p><table style="width:100%;border-collapse:collapse;margin:10px 0;font-size:12.5px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Feature</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">📜 Old IEEE 829</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">🌐 New 29119</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">Approach</td><td style="padding:6px 8px;">Document-based</td><td style="padding:6px 8px;">Process-based</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">Structure</td><td style="padding:6px 8px;">Fixed documents</td><td style="padding:6px 8px;">Flexible phases</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">Test design</td><td style="padding:6px 8px;">Not separate</td><td style="padding:6px 8px;">Separate phase</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">Execution</td><td style="padding:6px 8px;">Log-based</td><td style="padding:6px 8px;">Process + tools</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">Defects</td><td style="padding:6px 8px;">Test Incident Report</td><td style="padding:6px 8px;">Integrated in lifecycle</td></tr><tr style="background:var(--bg-warm);"><td style="padding:6px 8px;font-weight:600;">Used in</td><td style="padding:6px 8px;">Traditional projects</td><td style="padding:6px 8px;">Agile + modern systems</td></tr></tbody></table><div style="background:var(--bg-warm);padding:12px 14px;border-radius:8px;margin:10px 0;font-size:12.5px;"><strong>What do those acronyms mean?</strong><br>🔧 <strong>IEEE</strong> = Institute of Electrical &amp; Electronics Engineers<br>🌍 <strong>ISO</strong> = International Organization for Standardization (quality management, manufacturing, security)<br>⚡ <strong>IEC</strong> = International Electrotechnical Commission (focus on communications + electronics)</div><p><strong>📂 Free alternative:</strong> <span class="key-term">ReadySET</span> (Tigris) — open-source templates the textbook uses for case studies. No subscription required.</p><div class="callout">No single template fits all situations. It's the <strong>thought behind the planning</strong> that matters, not blind template-following.</div><div class="zh-note">IEEE 829（旧版 1998，文档导向）→ ISO/IEC/IEEE 29119（现代，流程导向 + 适合 Agile）。免费替代：ReadySET。模板不是关键，思考才是。</div>`},
{title:"📂 IEEE 829's 8 Test Documents",ref:"pp.90–92",content:`<p>The 8 documents defined by IEEE 829-1998. Together they cover the full test lifecycle.</p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:12.5px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);width:30px;">#</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Document</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Purpose</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--blue);">1</td><td style="padding:6px 8px;"><strong>Test Plan</strong></td><td style="padding:6px 8px;">Scope, approach, resources, schedule, risks</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--blue);">2</td><td style="padding:6px 8px;"><strong>Test Design Specification</strong></td><td style="padding:6px 8px;">Test conditions + coverage</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--blue);">3</td><td style="padding:6px 8px;"><strong>Test Case Specification</strong></td><td style="padding:6px 8px;">Inputs, execution steps, expected results</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--blue);">4</td><td style="padding:6px 8px;"><strong>Test Procedure Specification</strong></td><td style="padding:6px 8px;">Step-by-step execution instructions</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--orange);">5</td><td style="padding:6px 8px;"><strong>Test Item Transmittal Report</strong></td><td style="padding:6px 8px;">Tracks delivery of software to test team</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--orange);">6</td><td style="padding:6px 8px;"><strong>Test Log</strong></td><td style="padding:6px 8px;">Records execution results + events during test</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--red);">7</td><td style="padding:6px 8px;"><strong>Test Incident Report</strong></td><td style="padding:6px 8px;">Documents defects/bugs found</td></tr><tr style="background:var(--bg-warm);"><td style="padding:6px 8px;font-weight:700;color:var(--red);">8</td><td style="padding:6px 8px;"><strong>Test Summary Report</strong></td><td style="padding:6px 8px;">Final summary + overall quality verdict</td></tr></tbody></table><div class="callout"><strong>Three groupings:</strong><br>🔵 1-4: <em>Planning &amp; Design</em> (before execution)<br>🟠 5-6: <em>Tracking</em> (during execution)<br>🔴 7-8: <em>Reporting</em> (during + after execution)</div><p><strong>📋 In practice (your SRS template):</strong> Real-world IEEE 829-style plans expand into ~<strong>19 sections</strong>: Document Control · Introduction · Test Items · Features TO Test · Features NOT to test · Objectives · Sources of Expertise · Test Data · Environment · Strategy · Entry/Exit Criteria · Suspension/Resumption · Deliverables · Risks &amp; Contingency · Resource Planning · Testing by Phase · Test Case Specifications · Test Log · Test Incident Report · Approval. The 8 "documents" become 19 "sections" of one master plan.</p><div class="zh-note">IEEE 829 的 8 个文档：① 计划 ② 设计规范 ③ 用例规范 ④ 流程规范 ⑤ 移交报告 ⑥ 日志 ⑦ 事件报告 ⑧ 总结。分三组：计划 / 执行中 / 报告。实战中常扩展成 19 个章节（一个总计划文档）。</div>`},
{title:"🏦 Real Case: HSBC Part 2 — Design a Test Plan",ref:"Module 4 case",content:`<p>Recall from Unit 3: <strong>HSBC's Feb 27, 2017 outage</strong> hit 39M customers globally. In Part 2, the question becomes: <strong>what test plan would have prevented it?</strong></p><div style="background:var(--bg-warm);padding:14px 18px;border-radius:10px;margin:14px 0;font-size:13.5px;border-left:3px solid var(--accent);"><strong style="color:var(--accent-dim);">🎯 Your task:</strong> Build a test plan using the 10 items from this chapter, then write 10 test cases covering the highest-risk scenarios.</div><p><strong>Skeleton answer using the 10 items:</strong></p><table style="width:100%;border-collapse:collapse;margin:10px 0;font-size:12.5px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);width:30px;">#</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Item</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">HSBC Application</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--accent);">1</td><td style="padding:6px 8px;">Systems</td><td style="padding:6px 8px;font-style:italic;">Online banking portal + mobile app + backend auth + transaction APIs</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--accent);">2</td><td style="padding:6px 8px;">Objectives</td><td style="padding:6px 8px;font-style:italic;">Verify 99.99% uptime, &lt;3s response, transaction integrity</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--accent);">7</td><td style="padding:6px 8px;">Test Environment</td><td style="padding:6px 8px;font-style:italic;">Production-mirror with realistic Monday-morning load</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--accent);">8</td><td style="padding:6px 8px;">Strategy (Chessboard)</td><td style="padding:6px 8px;font-style:italic;">All 4 approaches — heavy emphasis on Performance + Black Box</td></tr><tr><td style="padding:6px 8px;font-weight:700;color:var(--accent);">9</td><td style="padding:6px 8px;">Phase-Wise Details</td><td style="padding:6px 8px;font-style:italic;">Per release: regression → load test → canary → full deploy</td></tr></tbody></table><p><strong>📝 Sample 10 high-risk test cases:</strong></p><div style="background:var(--bg-warm);padding:12px 16px;border-radius:8px;margin:8px 0;font-size:12.5px;line-height:1.8;">TC-01: Login with valid credentials &nbsp;·&nbsp; TC-02: Login with wrong password (lockout)<br>TC-03: Wire transfer £1 → confirm receipt &nbsp;·&nbsp; TC-04: Wire transfer with insufficient funds<br>TC-05: View statement (1000 transactions) &nbsp;·&nbsp; TC-06: Concurrent login from 10 devices<br>TC-07: Session timeout after 5 min idle &nbsp;·&nbsp; TC-08: Backend API responds &lt;200ms<br>TC-09: 50,000 concurrent logins (load) &nbsp;·&nbsp; TC-10: Failover to backup datacenter</div><div class="callout important"><strong>Lessons applied:</strong> The plan covers ALL 4 chess pieces, has realistic environment (item #7), and weighs Performance heavily (item #8) — exactly what HSBC under-tested.</div><div class="zh-note">HSBC Part 2 实战：用本章 10 项写一份测试计划，再写 10 个高风险测试用例。重点：环境像生产、4 种方法都用、性能压力别省。</div>`}
],quiz:[
{type:"mc",q:"A test plan primarily answers:",options:["Which programming language to use","WHAT to test, HOW, WHEN, and WHO","How many defects to expect","Which servers to buy"],answer:1,explanation:"Test plan = WHAT (scope) + HOW (strategy / chess board) + WHEN (schedule) + WHO (roles)."},
{type:"mc",q:"The test plan is described as a 'critical intermediate step' between what and what?",options:["Coding and deployment","Test strategy and test cases","Requirements and design","Manual and automated testing"],answer:1,explanation:"Test plan sits BETWEEN strategy (from Unit 3) and test cases (the HOW). Skipping it is like a dev jumping from design to coding — common mistake."},
{type:"mc",q:"Which is NOT one of the 10 test plan items?",options:["Testing scope","Sources of test data","Detailed source code review checklist","Testing strategy chess board"],answer:2,explanation:"Source code review checklists are not part of the test plan. The 10 items focus on what/how/when/who/where for testing."},
{type:"mc",q:"In a test plan, 'out of scope' items typically include:",options:["The most critical features","High-cost, low-risk items","Items that fall outside the test plan's focus","Both b and c"],answer:3,explanation:"Item #3 'Scope &amp; Limitations' includes BOTH explicit out-of-scope items (e.g., external payment gateway not tested) AND high-cost/low-risk items not worth testing budget."},
{type:"mc",q:"Item #9 of the test plan is special because:",options:["It's the largest single item","It repeats for every development phase, each with 7 sub-items","It's optional","It's only used in waterfall"],answer:1,explanation:"Item #9 is &lt;Repeated&gt; — for each development phase you write 7 sub-items (a-g): phase name, start criteria, end criteria, case list, writing schedule, execution schedule, reporting schedule."},
{type:"sa",q:"List the 7 sub-items (a–g) under Test Plan Item #9 (phase-wise details).",sampleAnswer:"a) Development phase name\nb) Start criteria — when can we start testing?\nc) End criteria — when are we done?\nd) Draft test case list (IDs + titles + descriptions)\ne) Draft test case writing schedule\nf) Draft test case execution schedule\ng) Draft results analysis + reporting schedule",keywords:["phase","start","end","case list","writing","execution","reporting","schedule"]},
{type:"mc",q:"Test cases start ____ and become ____ as development progresses.",options:["Detailed, abstract","High-level, detailed","Manual, automated","Long, short"],answer:1,explanation:"Test cases start HIGH-LEVEL (based on business requirements, risks, specs) then get DETAILED (step-by-step instructions with expected results) as development progresses."},
{type:"mc",q:"In the 15-item test case structure, items 13–15 are special because they are:",options:["Required from the start","Placeholders filled in DURING/AFTER execution","Optional metadata","Only for automated tests"],answer:1,explanation:"Items 13-15 are &lt;Placeholders&gt; — first attempt date, # attempts, defects found, success y/n. They're filled AFTER execution to prove the test ran and what happened."},
{type:"mc",q:"Why should test step actions avoid absolute screen coordinates?",options:["Coordinates take too long to type","Different monitors / resolutions distort layout, so tests fail unnecessarily","Screen positions are illegal under IEEE 829","Coordinates are only allowed for white box tests"],answer:1,explanation:"Screen-dependent steps (click at 450,320) break when the UI is resized, restyled, or moved. Use stable element identifiers (id, data-testid) instead. Only OK if you're explicitly testing layout."},
{type:"mc",q:"When expected ≠ actual results, the step:",options:["Passed","Failed — and 3 possible causes must be investigated","Was skipped","Times out"],answer:1,explanation:"Mismatch = failed. The 3 causes: ① Faulty test design (tester error) ② Ambiguous requirements ③ Genuine software defect. Always investigate in that order."},
{type:"sa",q:"List the 3 possible causes when a test step 'fails'. Why investigate them in order?",sampleAnswer:"1. Faulty test design (mistake in the test case itself).\n2. Ambiguous or unclear requirements.\n3. Genuine program error (software defect).\n\nWhy in order: Always suspect yourself FIRST — check if your test is wrong before blaming the spec or filing a bug. Filing fake bugs wastes developer time and erodes their trust in the test team's reports.",keywords:["test design","ambiguous","requirements","defect","order","suspect","fake","trust"]},
{type:"mc",q:"The 'Bathtub Diagram' shows that testing PLANNING peaks during:",options:["Coding phase","Deployment phase","Analysis + Design (early)","Maintenance phase"],answer:2,explanation:"The bathtub shape: planning + case writing peak EARLY (analysis/design), execution peaks LATE (final construction/deployment). Middle is the refinement valley."},
{type:"mc",q:"Which testing standard is the CURRENT international standard (replacing IEEE 829-1998)?",options:["ISO 9001","ISO/IEC/IEEE 29119","CMMI Level 3","RFC 2616"],answer:1,explanation:"ISO/IEC/IEEE 29119 is the current standard (2013+), jointly created by ISO + IEC + IEEE. IEEE 829-1998 is still taught but is older."},
{type:"mc",q:"IEEE 829-1998 defines how many standard test documents?",options:["5","8","10","15"],answer:1,explanation:"8 documents: Test Plan, Test Design Spec, Test Case Spec, Test Procedure Spec, Test Item Transmittal Report, Test Log, Test Incident Report, Test Summary Report."},
{type:"mc",q:"Which IEEE 829 document records defects/bugs discovered during testing?",options:["Test Log","Test Summary Report","Test Incident Report","Test Plan"],answer:2,explanation:"Test Incident Report — documents defects found. Test Log records all events (pass/fail). Test Summary Report gives the final verdict on quality."},
{type:"mc",q:"The textbook uses which (FREE) standard for case studies?",options:["IEEE 829-1998","ISO 9001","ReadySET (Tigris Open Source)","CMMI Level 3"],answer:2,explanation:"ReadySET (by Tigris) is open-source and free. Used by the textbook because IEEE 829 requires a paid subscription."},
{type:"sa",q:"What is the difference between a test plan and a test case?",sampleAnswer:"A test plan describes WHAT will be tested and WHY — scope, strategy, resources, schedules, the 10 items at a high level. One per project. A test case describes HOW to execute one specific test — step-by-step actions, expected results, actual results, the 15 items in detail. Many test cases per project, one per testing activity. Plan = map; Case = steps.",keywords:["what","why","how","high-level","detailed","steps","scope","one","many","map"]},
{type:"sa",q:"In the e-commerce checkout Bathtub example, name what testing activity happens at EACH of the 4 phases.",sampleAnswer:"Analysis: write test plan + draft test cases (planning peak). Design: write detailed test cases for payment success/failure scenarios. Coding: refine cases, then execute functional + integration tests. Deployment: execute UAT + performance tests (execution peak). The shape: high → medium → medium → high = bathtub.",keywords:["analysis","plan","design","write cases","coding","execute","deployment","UAT","performance"]},
{type:"sa",q:"SCENARIO: You execute a test on the LMS book-return feature. Expected: 'Returned' status appears. Actual: page crashes. Walk through how you investigate the 3 possible causes.",sampleAnswer:"Step 1: Re-read MY test case for typos/wrong inputs. Maybe I entered the wrong book ID or skipped a setup step. Re-run the test. If still crashes... Step 2: Check the requirements spec — does it actually say 'Returned' status should appear, or did I assume? Talk to the business expert (librarian) to confirm. If spec is clear... Step 3: File a defect with detailed steps, expected vs actual, environment details. Developer takes it from there. The order saves time and protects credibility.",keywords:["re-read","my test","setup","requirements","spec","librarian","file","defect","steps","credibility"]},
{type:"mc",q:"SCENARIO: A team writes test case TC-001 that says 'click at coordinates (200, 400)'. The next sprint, designers redesign the page. TC-001 breaks. What's the root cause?",options:["The designer made a mistake","The test was screen-dependent — should have used element identifiers","Performance was poor","The test plan was missing item #9"],answer:1,explanation:"The test was brittle because it used absolute coordinates instead of stable element IDs (id, data-testid). Tests should be layout-independent. Designer changing the UI is normal — your test should survive it."},
{type:"mc",q:"SCENARIO: HSBC suffers an outage. Which test plan items, if properly executed, would have most likely caught it?",options:["Items #1 + #2 (systems + objectives)","Items #6 + #8 (test data + chess board strategy)","Items #7 + #8 (production-mirror environment + performance/load testing)","Items #4 + #5 (business + dev expertise)"],answer:2,explanation:"#7 (test environment must mirror production) + #8 (strategy chess board including Performance testing under realistic load) would catch the capacity/integration failures HSBC missed. The textbook lesson: under-testing the production-like environment is how outages slip through."},
{type:"sa",q:"Which 3 inputs feed into creating a test case? Give one LMS example for each.",sampleAnswer:"1. Business Requirements — what the system should do. LMS example: 'User can borrow up to 5 books.'\n2. Business Risks — what can go wrong. LMS example: 'Student borrows the same book twice (data corruption).'\n3. Software Specifications — technical rules. LMS example: 'Book ID is 10 alphanumeric characters.' These 3 inputs combine into step-by-step test instructions.",keywords:["business requirements","risks","specifications","LMS","borrow","example","technical"]},
{type:"mc",q:"In the SRS template, UAT + performance testing happens in which environment?",options:["Development","QA / Test","Staging","Production"],answer:2,explanation:"Staging environment = the last stop before Production. UAT (business users approve) + performance testing both happen here on a production-like setup. Dev = unit tests, QA = functional/regression, Production = real users (monitoring only)."},
{type:"mc",q:"A payment-service crash blocks core checkout flow. The team should:",options:["Continue testing other features","SUSPEND testing — payment crash is a suspension criterion","File a low-priority bug and keep going","Demote the issue to backlog"],answer:1,explanation:"Suspension criteria include: system crash, critical defect blocking core features, DB failure, environment unavailable, payment service down. Resume when defects are fixed + verified + stable build deployed."},
{type:"sa",q:"Using the SRS estimation formula, calculate effort for 3 testers working 8 days. What does 'person-day' actually mean?",sampleAnswer:"Effort = testers × days = 3 × 8 = 24 person-days. A 'person-day' = one tester working one full day. It's how project managers price testing: if a tester costs $400/day, this work = $9,600. The formula deliberately ignores how many calendar days it takes (3 testers in parallel might finish in ~3 calendar days, but the BUDGET is still 24 person-days).",keywords:["3 × 8","24","person-day","one tester","one day","budget","calendar","parallel"]}
]});

// ============================================================
INTERACTIVES[4] = function(el) {
  let u4Tab = 0;
  const tabs = [
    {key:'bath',  icon:'🛁', label:'Bathtub Diagram'},
    {key:'plan',  icon:'📋', label:'Test Plan Explorer'},
    {key:'case',  icon:'📐', label:'Test Case Anatomy'},
    {key:'srs',   icon:'🏗️', label:'SRS Walkthrough'}
  ];

  // ---------- Widget 1: Bathtub Diagram Animator ----------
  const bathPhases = [
    {name:'Analysis',    devWork:'Define checkout process',          testAct:'📝 Write test plan + draft cases',           planAct:90, execAct:5,  color:'#4a7fb5'},
    {name:'Design',      devWork:'Design payment flow',              testAct:'✍️ Write detailed test cases',               planAct:75, execAct:10, color:'#7c6baf'},
    {name:'Coding',      devWork:'Implement payment system',         testAct:'🔄 Refine cases · 🧪 Unit + integration tests', planAct:30, execAct:55, color:'#c08530'},
    {name:'Final Constr',devWork:'Integrate + system testing',       testAct:'🚀 Functional + regression tests',           planAct:15, execAct:85, color:'#c25450'},
    {name:'Deployment',  devWork:'App goes live',                    testAct:'🚀 UAT + performance tests',                 planAct:10, execAct:95, color:'#3d8b5a'},
    {name:'Post-Impl',   devWork:'Monitoring + maintenance',         testAct:'👀 Passive monitoring · regression on fixes', planAct:20, execAct:40, color:'#4a9e6e'}
  ];
  let bathStep = -1;
  let bathTimer = null;
  let bathSel = null;

  function renderBath() {
    let h = '<p style="font-size:13px;color:var(--text-dim);margin-bottom:12px;">Click <strong>Play</strong> to watch the U-shaped curve form. Click any bar to see the phase details.</p>';
    h += '<div style="display:flex;gap:10px;margin-bottom:14px;">';
    h += '<button onclick="window._u4bathPlay()" '+(bathStep>=0&&bathStep<bathPhases.length?'disabled':'')+' style="cursor:pointer;padding:8px 16px;border-radius:8px;border:none;background:var(--accent);color:#fff;font-weight:600;font-size:13px;opacity:'+(bathStep>=0&&bathStep<bathPhases.length?0.5:1)+';">▶️ Play Animation</button>';
    h += '<button onclick="window._u4bathReset()" style="cursor:pointer;padding:8px 16px;border-radius:8px;border:1px solid var(--border);background:var(--surface);color:var(--text);font-size:13px;">🔁 Reset</button>';
    h += '<div style="flex:1;display:flex;gap:14px;align-items:center;justify-content:flex-end;font-size:11.5px;color:var(--text-dim);"><span><span style="display:inline-block;width:12px;height:12px;background:var(--blue);border-radius:3px;vertical-align:middle;"></span> Planning</span><span><span style="display:inline-block;width:12px;height:12px;background:var(--red);border-radius:3px;vertical-align:middle;"></span> Execution</span></div>';
    h += '</div>';
    // The chart
    h += '<div style="background:linear-gradient(180deg,var(--bg-warm),var(--surface));padding:18px 14px;border-radius:12px;border:1px solid var(--border-light);">';
    h += '<div style="font-size:11px;color:var(--text-dim);margin-bottom:8px;font-weight:700;text-transform:uppercase;letter-spacing:1px;">📊 Testing Activity Over SDLC Phases</div>';
    h += '<div style="display:grid;grid-template-columns:30px repeat('+bathPhases.length+',1fr);gap:6px;align-items:end;height:180px;margin-bottom:8px;">';
    h += '<div style="display:flex;flex-direction:column;justify-content:space-between;font-size:9px;color:var(--text-dim);text-align:right;padding-right:4px;height:100%;"><span>100%</span><span>50%</span><span>0%</span></div>';
    bathPhases.forEach((p,i) => {
      const visible = i <= bathStep;
      const sel = bathSel === i;
      const planH = visible ? p.planAct : 0;
      const execH = visible ? p.execAct : 0;
      h += '<div onclick="window._u4bathSel('+i+')" style="cursor:pointer;display:flex;gap:2px;align-items:end;height:100%;opacity:'+(visible?1:0.25)+';transition:all .8s;'+(sel?'transform:translateY(-4px);':'')+'">';
      h += '<div title="Planning activity" style="flex:1;background:linear-gradient(180deg,var(--blue),'+p.color+');height:'+planH+'%;border-radius:4px 4px 0 0;transition:height .8s ease-out;box-shadow:'+(sel?'0 0 0 2px var(--accent)':'none')+';"></div>';
      h += '<div title="Execution activity" style="flex:1;background:linear-gradient(180deg,var(--red),'+p.color+');height:'+execH+'%;border-radius:4px 4px 0 0;transition:height .8s ease-out;box-shadow:'+(sel?'0 0 0 2px var(--accent)':'none')+';"></div>';
      h += '</div>';
    });
    h += '</div>';
    h += '<div style="display:grid;grid-template-columns:30px repeat('+bathPhases.length+',1fr);gap:6px;font-size:10.5px;color:var(--text);text-align:center;font-weight:600;margin-top:6px;">';
    h += '<div></div>';
    bathPhases.forEach((p,i) => {
      h += '<div style="color:'+(i<=bathStep?p.color:'var(--text-light)')+';transition:color .8s;">'+p.name+'</div>';
    });
    h += '</div>';
    h += '</div>';
    // Detail panel
    if (bathSel !== null && bathSel <= bathStep) {
      const p = bathPhases[bathSel];
      h += '<div style="margin-top:14px;padding:14px 18px;border-radius:10px;background:var(--bg-warm);border-left:4px solid '+p.color+';font-size:13px;">';
      h += '<div style="font-weight:700;color:'+p.color+';margin-bottom:8px;font-size:14px;">'+p.name+'</div>';
      h += '<div style="display:grid;grid-template-columns:1fr 1fr;gap:14px;">';
      h += '<div><div style="font-size:11px;color:var(--text-dim);font-weight:700;text-transform:uppercase;letter-spacing:1px;margin-bottom:4px;">💻 Dev Work</div><div>'+p.devWork+'</div></div>';
      h += '<div><div style="font-size:11px;color:var(--text-dim);font-weight:700;text-transform:uppercase;letter-spacing:1px;margin-bottom:4px;">🧪 Test Activity</div><div>'+p.testAct+'</div></div>';
      h += '</div></div>';
    } else if (bathStep >= bathPhases.length - 1) {
      h += '<div style="margin-top:14px;padding:14px 18px;border-radius:10px;background:var(--accent-bg);font-size:13px;color:var(--accent-dim);"><strong>💡 Notice the U-shape!</strong> Planning peaks early (Analysis/Design), execution peaks late (Final Construction/Deployment). The middle is the "valley" of refinement. Click any phase bar to drill in.</div>';
    } else if (bathStep < 0) {
      h += '<div style="margin-top:14px;padding:14px 18px;border-radius:10px;background:var(--surface2);font-size:13px;color:var(--text-dim);">👆 Press <strong>Play</strong> to animate the bathtub curve forming.</div>';
    }
    return h;
  }
  window._u4bathPlay = function(){
    if (bathTimer) clearInterval(bathTimer);
    bathStep = -1;
    bathSel = null;
    rerender();
    bathTimer = setInterval(()=>{
      bathStep++;
      if (bathStep >= bathPhases.length) { clearInterval(bathTimer); bathTimer=null; bathStep = bathPhases.length-1; }
      rerender();
    }, 700);
  };
  window._u4bathReset = function(){
    if (bathTimer) { clearInterval(bathTimer); bathTimer=null; }
    bathStep = -1;
    bathSel = null;
    rerender();
  };
  window._u4bathSel = function(i){ bathSel = i; rerender(); };

  // ---------- Widget 2: Test Plan Item Explorer ----------
  const planItems = [
    {n:1,name:'Systems to be Tested',lms:'Library Management System (LMS) — book issue/return module',ecom:'E-commerce checkout (catalog + cart + payment)',tip:'Be specific about which subsystem — "the LMS" is too vague.'},
    {n:2,name:'Testing Objectives',lms:'Ensure book issue/return works correctly (risk: lost books)',ecom:'Verify orders complete + payment succeeds (risk: lost revenue)',tip:'Tie every objective to a business RISK, not just "make sure it works".'},
    {n:3,name:'Scope &amp; Limitations',lms:'✅ Book management · ❌ Payment gateway (out of scope)',ecom:'✅ Web checkout · ❌ Third-party shipping API',tip:'Explicitly list OUT-OF-SCOPE items to prevent expectation creep.'},
    {n:4,name:'Business Expertise',lms:'Librarian validates borrowing rules + late-fee policy',ecom:'Product manager confirms pricing + discount logic',tip:'Identify by NAME — "the librarian" not "someone from the library".'},
    {n:5,name:'Development Expertise',lms:'Developer explains DB schema + relationships',ecom:'Backend lead explains payment API contracts',tip:'Devs often resist this — frame it as "I want to test your code correctly".'},
    {n:6,name:'Test Data Sources',lms:'Sample student records + book inventory DB',ecom:'Anonymized order history + test credit cards (Stripe test mode)',tip:'Test data must be realistic AND non-sensitive. No real PII!'},
    {n:7,name:'Test Environment',lms:'Same web server, DB, browser config as production',ecom:'Staging env mirroring prod hardware + 3rd-party stubs',tip:'A "similar" environment is NOT enough — must mirror prod.'},
    {n:8,name:'Testing Strategy (Chess Board)',lms:'Static + functional + integration + security + performance',ecom:'All 4 chess pieces — heavy on performance (Black Friday traffic)',tip:'Use the 2D/3D chess board from Unit 3. Reference it directly.'},
    {n:9,name:'&lt;Repeated&gt; Phase-Wise Details',lms:'Per phase: 7 sub-items (a-g) — start/end criteria, schedules',ecom:'Same — Sprint 1, Sprint 2, etc., each with 7 sub-items',tip:'This is the BIG item. Skipping sub-items is the #1 cause of missed tests.'},
    {n:10,name:'Overall Testing Schedule',lms:'Master Gantt chart combining all phase activities',ecom:'Project timeline showing all sprints + UAT + release dates',tip:'Expect 3–4 weeks of extra time by ⅓ mark. Build in buffer.'}
  ];
  let planScen = 'lms';
  let planSel = 0;

  function renderPlan() {
    let h = '<p style="font-size:13px;color:var(--text-dim);margin-bottom:12px;">Click any of the 10 items to see expanded examples. Switch scenario to compare contexts.</p>';
    h += '<div style="display:flex;gap:6px;margin-bottom:14px;">';
    h += '<button onclick="window._u4planScen(\'lms\')" style="cursor:pointer;padding:7px 14px;border-radius:8px;border:2px solid '+(planScen==='lms'?'var(--accent)':'var(--border-light)')+';background:'+(planScen==='lms'?'var(--accent-bg)':'var(--surface)')+';color:'+(planScen==='lms'?'var(--accent-dim)':'var(--text-dim)')+';font-weight:600;font-size:12.5px;">📚 Library System</button>';
    h += '<button onclick="window._u4planScen(\'ecom\')" style="cursor:pointer;padding:7px 14px;border-radius:8px;border:2px solid '+(planScen==='ecom'?'var(--accent)':'var(--border-light)')+';background:'+(planScen==='ecom'?'var(--accent-bg)':'var(--surface)')+';color:'+(planScen==='ecom'?'var(--accent-dim)':'var(--text-dim)')+';font-weight:600;font-size:12.5px;">🛒 E-commerce</button>';
    h += '</div>';
    // Item grid
    h += '<div style="display:grid;grid-template-columns:repeat(5,1fr);gap:6px;margin-bottom:14px;">';
    planItems.forEach((p,i) => {
      const sel = i === planSel;
      h += '<button onclick="window._u4planSel('+i+')" style="cursor:pointer;padding:10px 6px;border-radius:8px;border:2px solid '+(sel?'var(--accent)':'var(--border-light)')+';background:'+(sel?'var(--accent-bg)':'var(--surface)')+';color:'+(sel?'var(--accent-dim)':'var(--text)')+';font-size:11px;font-weight:600;transition:all .15s;line-height:1.3;text-align:center;">';
      h += '<div style="font-size:18px;font-weight:700;color:'+(sel?'var(--accent-dim)':'var(--accent)')+';">'+p.n+'</div>';
      h += '<div>'+p.name.split(' ').slice(0,2).join(' ')+'</div>';
      h += '</button>';
    });
    h += '</div>';
    // Detail
    const it = planItems[planSel];
    const ex = planScen==='lms' ? it.lms : it.ecom;
    const scen = planScen==='lms' ? 'Library System' : 'E-commerce Checkout';
    h += '<div style="background:var(--bg-warm);padding:16px 20px;border-radius:10px;border-left:4px solid var(--accent);">';
    h += '<div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;">';
    h += '<div style="width:36px;height:36px;border-radius:8px;background:var(--accent);color:#fff;display:flex;align-items:center;justify-content:center;font-size:18px;font-weight:700;">'+it.n+'</div>';
    h += '<div style="font-size:15px;font-weight:700;color:var(--accent-dim);">'+it.name+'</div>';
    h += '</div>';
    h += '<div style="margin-bottom:10px;font-size:13px;"><strong style="color:var(--text-dim);">'+scen+' example:</strong><br>'+ex+'</div>';
    h += '<div style="padding:10px 14px;background:var(--accent-bg);border-radius:8px;font-size:12.5px;color:var(--accent-dim);"><strong>💡 Tip:</strong> '+it.tip+'</div>';
    h += '</div>';
    return h;
  }
  window._u4planScen = function(s){ planScen=s; rerender(); };
  window._u4planSel = function(i){ planSel=i; rerender(); };

  // ---------- Widget 3: Test Case Anatomy ----------
  const caseItems = [
    {n:1,  group:'identity', label:'Test Case ID',        desc:'Unique ID from test plan',                         ex:'TC-LMS-001',                 placeholder:false},
    {n:2,  group:'identity', label:'Title',              desc:'Unique title from test plan',                       ex:'Issue book to valid student',placeholder:false},
    {n:3,  group:'identity', label:'Description',         desc:'Brief description from test plan',                 ex:'Verifies book.status changes to "Issued" after valid issue', placeholder:false},
    {n:4,  group:'identity', label:'Development Phase',   desc:'Which phase this runs in (from test plan)',        ex:'Preliminary Construction',   placeholder:false},
    {n:5,  group:'setup',    label:'Testing Goals',       desc:'Specific goals + measures of achievement',         ex:'Verify status transition + DB write (Pass = both occur)', placeholder:false},
    {n:6,  group:'setup',    label:'Suggested Test Data', desc:'What data to use',                                  ex:'Student #S12345, Book #B98765',placeholder:false},
    {n:7,  group:'setup',    label:'Suggested Test Tools',desc:'Manual or automated tools',                         ex:'Selenium + pytest',          placeholder:false},
    {n:8,  group:'procedure',label:'Startup Procedure',   desc:'How to set up before running',                      ex:'Login as librarian, navigate to /issue', placeholder:false},
    {n:9,  group:'procedure',label:'Closedown Procedure', desc:'How to clean up after running',                     ex:'Logout, clear browser cache', placeholder:false},
    {n:10, group:'procedure',label:'Reset / Rerun Procedure',desc:'How to reset for repeated runs',                ex:'Reset Book #B98765 status to "Available" in DB', placeholder:false},
    {n:11, group:'procedure',label:'(reserved)',          desc:'Often used for environment-specific notes',         ex:'(varies by team)',           placeholder:false},
    {n:12, group:'execution',label:'Repeated Steps',      desc:'For each step: # · action · expected · actual',     ex:'1. Click "Issue" → expect status="Issued" → actual: ?', placeholder:false},
    {n:13, group:'tracking', label:'First Attempt Date / Time',desc:'When the test was first run',                ex:'(filled after execution)',   placeholder:true},
    {n:14, group:'tracking', label:'# Attempts to Succeed',desc:'How many runs needed',                            ex:'(filled after execution)',   placeholder:true},
    {n:15, group:'tracking', label:'Defects Discovered + Success y/n',desc:'Bugs found, final verdict',           ex:'(filled after execution)',   placeholder:true}
  ];
  const caseGroups = {
    identity:  {label:'📋 Identity (1-4)',   color:'#4a7fb5', desc:'Copied from test plan — uniquely identifies the case'},
    setup:     {label:'🎯 Setup (5-7)',      color:'#7c6baf', desc:'What you need before running'},
    procedure: {label:'⚙️ Procedure (8-11)', color:'#c08530', desc:'How to start, stop, reset'},
    execution: {label:'🔁 Execution (12)',   color:'#3d8b5a', desc:'The actual test steps + expected/actual results'},
    tracking:  {label:'📝 Tracking (13-15)', color:'#c25450', desc:'<Placeholders> filled AFTER execution — proves the test ran'}
  };
  let caseSel = 0;

  function renderCase() {
    let h = '<p style="font-size:13px;color:var(--text-dim);margin-bottom:12px;">Click any item to see its purpose + LMS example. Color-coded by group. Items 13-15 are &lt;Placeholders&gt; filled AFTER execution.</p>';
    // Group legend
    h += '<div style="display:flex;flex-wrap:wrap;gap:8px;margin-bottom:14px;">';
    Object.keys(caseGroups).forEach(k => {
      const g = caseGroups[k];
      h += '<div style="display:inline-flex;align-items:center;gap:6px;padding:5px 10px;background:'+g.color+'22;border:1px solid '+g.color+';border-radius:6px;font-size:11px;color:'+g.color+';font-weight:600;">'+g.label+'</div>';
    });
    h += '</div>';
    // Item grid
    h += '<div style="display:grid;grid-template-columns:repeat(5,1fr);gap:6px;margin-bottom:14px;">';
    caseItems.forEach((it,i) => {
      const sel = i === caseSel;
      const g = caseGroups[it.group];
      h += '<button onclick="window._u4caseSel('+i+')" style="cursor:pointer;padding:10px 4px;border-radius:8px;border:2px solid '+(sel?g.color:'var(--border-light)')+';background:'+(sel?g.color+'22':'var(--surface)')+';color:'+(sel?g.color:'var(--text)')+';font-size:11px;font-weight:600;transition:all .15s;line-height:1.2;text-align:center;position:relative;">';
      h += '<div style="font-size:16px;font-weight:700;color:'+g.color+';margin-bottom:2px;">'+it.n+'</div>';
      h += '<div style="font-size:9.5px;line-height:1.2;">'+it.label.split(' ').slice(0,3).join(' ')+'</div>';
      if (it.placeholder) h += '<div style="position:absolute;top:2px;right:4px;font-size:10px;">📝</div>';
      h += '</button>';
    });
    h += '</div>';
    // Detail
    const it = caseItems[caseSel];
    const g = caseGroups[it.group];
    h += '<div style="background:var(--bg-warm);padding:16px 20px;border-radius:10px;border-left:4px solid '+g.color+';">';
    h += '<div style="display:flex;align-items:center;gap:10px;margin-bottom:8px;flex-wrap:wrap;">';
    h += '<div style="width:36px;height:36px;border-radius:8px;background:'+g.color+';color:#fff;display:flex;align-items:center;justify-content:center;font-size:18px;font-weight:700;">'+it.n+'</div>';
    h += '<div style="font-size:15px;font-weight:700;color:'+g.color+';">'+it.label+'</div>';
    if (it.placeholder) h += '<div style="font-size:10px;background:var(--orange-bg);color:var(--orange);padding:2px 8px;border-radius:4px;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;">📝 Placeholder</div>';
    h += '</div>';
    h += '<div style="margin-bottom:10px;font-size:13px;color:var(--text);"><strong>Purpose:</strong> '+it.desc+'</div>';
    h += '<div style="padding:10px 14px;background:var(--surface);border:1px solid var(--border-light);border-radius:8px;font-size:12.5px;font-family:\'JetBrains Mono\',monospace;color:var(--text);"><strong style="font-family:\'Source Sans 3\',sans-serif;color:var(--text-dim);">LMS Example:</strong> '+it.ex+'</div>';
    h += '<div style="margin-top:10px;padding:8px 12px;background:'+g.color+'22;border-radius:6px;font-size:11.5px;color:'+g.color+';"><strong>Group:</strong> '+g.desc+'</div>';
    h += '</div>';
    return h;
  }
  window._u4caseSel = function(i){ caseSel=i; rerender(); };

  // ---------- Widget 4: SRS Walkthrough (Real Test Plan Example) ----------
  const srsPhases = [
    {key:'req', label:'1. Requirements', color:'#4a7fb5', prefix:'RTC', schedule:'Weeks 1–2',
      entry:['Requirements document approved','Business rules finalized','Testable requirements available'],
      exit:['Requirement reviews completed','Ambiguities resolved','Requirement defects documented'],
      cases:[
        {id:'RTC-001', title:'Requirement Completeness',  desc:'Verify ALL requirements are documented (no gaps)'},
        {id:'RTC-002', title:'Requirement Consistency',    desc:'Check for conflicting/contradictory requirements'},
        {id:'RTC-003', title:'Requirement Traceability',   desc:'Verify each requirement maps to a business goal'}
      ]},
    {key:'des', label:'2. Design', color:'#7c6baf', prefix:'DTC', schedule:'Weeks 3–4',
      entry:['Design documents completed','Database schema available','UI prototypes approved'],
      exit:['Design defects resolved','Architecture validated by review board'],
      cases:[
        {id:'DTC-001', title:'Database Design Validation', desc:'Verify table relationships + foreign keys'},
        {id:'DTC-002', title:'UI Design Validation',       desc:'Verify interface consistency across screens'},
        {id:'DTC-003', title:'API Design Validation',      desc:'Verify endpoint specifications + contract'}
      ]},
    {key:'dev', label:'3. Development', color:'#c08530', prefix:'DEV', schedule:'Weeks 5–7',
      entry:['Modules compiled successfully','Unit test environment available','Build deployed to QA'],
      exit:['All unit tests passed','Critical defects fixed'],
      cases:[
        {id:'DEV-001', title:'Student Login Test',         desc:'Verify valid + invalid login (7 steps in IEEE 829 case)'},
        {id:'DEV-002', title:'Course Registration Test',   desc:'Verify enrollment, prevent duplicates, handle full courses'},
        {id:'DEV-003', title:'Add/Drop Course Test',       desc:'Verify schedule modifications work correctly'},
        {id:'DEV-004', title:'Payment Validation Test',    desc:'Verify payment transactions + receipts'},
        {id:'DEV-005', title:'Timetable Generation Test',  desc:'Verify class schedule creation + conflicts'}
      ]},
    {key:'sys', label:'4. System Testing', color:'#3d8b5a', prefix:'SYS', schedule:'Weeks 8–9',
      entry:['All modules integrated','Stable build available','Test environment ready'],
      exit:['No critical defects open','Test coverage achieved','Exit criteria met'],
      cases:[
        {id:'SYS-001', title:'End-to-End Registration',    desc:'Complete registration workflow from login → confirmation'},
        {id:'SYS-002', title:'Concurrent User Test',       desc:'Multiple students registering simultaneously'},
        {id:'SYS-003', title:'Security Access Test',       desc:'Verify role-based authorization levels'},
        {id:'SYS-004', title:'Performance Load Test',      desc:'Simulate peak registration-period traffic'}
      ]},
    {key:'uat', label:'5. UAT', color:'#c25450', prefix:'UAT', schedule:'Week 10',
      entry:['System testing completed','UAT environment prepared','Business users assigned + trained'],
      exit:['Business approval received','UAT defects resolved','Sign-off signed'],
      cases:[
        {id:'UAT-001', title:'Student Registration Flow',  desc:'Real student validates registration end-to-end'},
        {id:'UAT-002', title:'Admin Operations',           desc:'Registrar validates admin workflows'},
        {id:'UAT-003', title:'Report Generation',          desc:'Reports match expected business outputs'}
      ]}
  ];
  let srsSel = 0;
  let srsCaseSel = null;

  function renderSRS() {
    const p = srsPhases[srsSel];
    let h = '<p style="font-size:13px;color:var(--text-dim);margin-bottom:12px;">Walk through a real Test Plan for the <strong>Student Registration System (SRS)</strong>. 5 phases, each with entry/exit criteria + test case IDs.</p>';
    // Phase tabs
    h += '<div style="display:flex;gap:4px;margin-bottom:14px;flex-wrap:wrap;">';
    srsPhases.forEach((ph,i)=>{
      const active = i===srsSel;
      h += '<button onclick="window._u4srsSel('+i+')" style="cursor:pointer;flex:1;min-width:110px;padding:10px 6px;border-radius:8px;border:2px solid '+(active?ph.color:'var(--border-light)')+';background:'+(active?'var(--bg-warm)':'var(--surface)')+';color:'+(active?ph.color:'var(--text-dim)')+';font-weight:700;font-size:11.5px;transition:all .15s;line-height:1.3;">'+ph.label+'</button>';
    });
    h += '</div>';
    // Phase header
    h += '<div style="background:'+p.color+'22;border:2px solid '+p.color+';border-radius:12px;padding:14px 18px;margin-bottom:12px;">';
    h += '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px;"><div style="font-size:16px;font-weight:700;color:'+p.color+';">'+p.label+'</div><div style="font-size:11.5px;color:var(--text-dim);background:var(--surface);padding:4px 10px;border-radius:14px;font-weight:600;">📅 '+p.schedule+'</div></div>';
    h += '</div>';
    // Entry / Exit criteria
    h += '<div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:12px;">';
    h += '<div style="background:var(--green-bg);border-radius:10px;padding:12px 14px;"><div style="font-size:11px;font-weight:700;color:var(--green);text-transform:uppercase;letter-spacing:1px;margin-bottom:6px;">✅ Entry Criteria</div><ul style="margin:0;padding-left:18px;font-size:12.5px;color:var(--text);line-height:1.6;">';
    p.entry.forEach(e=>{ h += '<li>'+e+'</li>'; });
    h += '</ul></div>';
    h += '<div style="background:var(--red-bg);border-radius:10px;padding:12px 14px;"><div style="font-size:11px;font-weight:700;color:var(--red);text-transform:uppercase;letter-spacing:1px;margin-bottom:6px;">🏁 Exit Criteria</div><ul style="margin:0;padding-left:18px;font-size:12.5px;color:var(--text);line-height:1.6;">';
    p.exit.forEach(e=>{ h += '<li>'+e+'</li>'; });
    h += '</ul></div></div>';
    // Test cases list
    h += '<div style="background:var(--surface);border:1px solid var(--border-light);border-radius:10px;padding:14px 16px;"><div style="font-size:11px;font-weight:700;color:var(--accent-dim);text-transform:uppercase;letter-spacing:1px;margin-bottom:10px;">📋 Draft Test Cases ('+p.prefix+'-xxx)</div>';
    p.cases.forEach((c,ci)=>{
      const sel = srsCaseSel === srsSel+'-'+ci;
      h += '<div onclick="window._u4srsCase(\''+srsSel+'-'+ci+'\')" style="cursor:pointer;padding:10px 12px;border-radius:8px;margin-bottom:6px;border:2px solid '+(sel?p.color:'var(--border-light)')+';background:'+(sel?p.color+'15':'var(--bg-warm)')+';transition:all .15s;">';
      h += '<div style="display:flex;align-items:center;gap:10px;"><span style="font-family:\'JetBrains Mono\',monospace;font-weight:700;color:'+p.color+';font-size:12px;background:var(--surface);padding:3px 8px;border-radius:5px;">'+c.id+'</span><span style="font-weight:600;font-size:13px;color:var(--text);">'+c.title+'</span></div>';
      if (sel) h += '<div style="margin-top:8px;font-size:12.5px;color:var(--text);padding-left:6px;border-left:3px solid '+p.color+';padding-left:10px;">'+c.desc+'</div>';
      h += '</div>';
    });
    h += '</div>';
    // Footer insight
    h += '<div style="margin-top:12px;padding:12px 16px;background:var(--accent-bg);border-radius:8px;font-size:12.5px;color:var(--accent-dim);"><strong>💡 Notice the ID prefixes:</strong> RTC=Requirements, DTC=Design, DEV=Development, SYS=System, UAT=User Acceptance. Just from the ID you know which phase &amp; environment a test belongs to.</div>';
    return h;
  }
  window._u4srsSel = function(i){ srsSel=i; srsCaseSel=null; rerender(); };
  window._u4srsCase = function(k){ srsCaseSel = (srsCaseSel===k?null:k); rerender(); };

  // ---------- Main render with tabs ----------
  function rerender() {
    let h = '<div style="display:flex;gap:2px;margin-bottom:18px;background:var(--surface2);padding:3px;border-radius:10px;width:fit-content;border:1px solid var(--border-light);flex-wrap:wrap;">';
    tabs.forEach((t,i) => {
      const active = i===u4Tab;
      h += '<button onclick="window._u4tab('+i+')" style="cursor:pointer;padding:8px 16px;border-radius:8px;border:none;background:'+(active?'var(--accent)':'transparent')+';color:'+(active?'#fff':'var(--text-dim)')+';font-size:13px;font-weight:600;transition:all .15s;">'+t.icon+' '+t.label+'</button>';
    });
    h += '</div>';
    h += '<div style="animation:u4fade 0.3s ease-out;">';
    if (u4Tab===0) h += renderBath();
    else if (u4Tab===1) h += renderPlan();
    else if (u4Tab===2) h += renderCase();
    else h += renderSRS();
    h += '</div>';
    h += '<style>@keyframes u4fade{from{opacity:0;transform:translateX(-8px);}to{opacity:1;transform:translateX(0);}}</style>';
    el.innerHTML = h;
  }
  window._u4tab = function(i){
    if (bathTimer) { clearInterval(bathTimer); bathTimer=null; }
    u4Tab=i; rerender();
  };
  rerender();
};

// ============================================================
// Unit 4: Test Planning
// (Indices: 0=Learning Obj, 1=What is Test Plan, 2=10 Items+LMS,
//  3=Item #9 Phase-Wise, 4=Test Case Creation, 5=15-Item Anatomy,
//  6=Step Actions, 7=Expected vs Actual, 8=Bathtub Diagram,
//  9=Entry/Exit/Suspension+Env+Estimation, 10=IEEE 829+ISO 29119,
//  11=8 Documents, 12=HSBC Part 2)
// ============================================================
MODERN_NOTES['4-1'] = {
  title: 'Lighter plans, same 10 items of thinking',
  year: '2026',
  content: 'Agile teams use lighter test plans — often just a Confluence page, a Jira epic, or a Notion doc — but the <strong>same 10 items of thinking</strong> still apply. Modern additions: <strong>BDD (Behavior-Driven Development)</strong> writes test cases in plain English ("Given… When… Then…") so business + tech share the same language (tools: Cucumber, SpecFlow). <strong>TDD (Test-Driven Development)</strong> writes tests BEFORE code (Red-Green-Refactor cycle). Both make "what to test" a living document, not a binder on a shelf.'
};
MODERN_NOTES['4-2'] = {
  title: 'Test management tools: TestRail, Zephyr, Xray',
  year: '2026',
  content: 'The 10 plan items live in modern <strong>test management platforms</strong>: <strong>TestRail</strong> (most popular standalone), <strong>Zephyr Scale</strong> (Jira-native), <strong>Xray</strong> (Jira-native, popular in EU), <strong>qTest</strong>. They auto-generate the "10 items" from your project metadata + link test cases to user stories. For pure-Agile shops, much of this is replaced by GitHub Issues + linked PR test files. Pick based on team size + Jira usage.'
};
MODERN_NOTES['4-3'] = {
  title: 'Phase-wise → Sprint-wise: one test plan per sprint',
  year: '2026',
  content: 'In Agile, Item #9 (&lt;Repeated&gt; per phase) becomes <strong>&lt;Repeated&gt; per sprint</strong>. Each 2-week sprint gets its own mini-plan: start criteria (story DoR — Definition of Ready), end criteria (DoD — Definition of Done), test case list (acceptance criteria), schedules built into the sprint board. The 7 sub-items (a-g) still exist — they\'re just compressed into one sprint planning meeting instead of months of phase planning.'
};
MODERN_NOTES['4-5'] = {
  title: 'Test cases as code: Cypress, Playwright, pytest',
  year: '2026',
  content: 'The 15-item format lives on in TestRail/Zephyr, but the cutting-edge approach is <strong>tests-as-code</strong>: write tests in JavaScript (Cypress, Playwright), Python (pytest), Java (JUnit) — the test IS the documentation. "Expected results" become assertions: <code>expect(result).toBe(expected)</code>. The 15 items map to code constructs: title → <code>describe()</code>, setup → <code>beforeEach()</code>, steps → <code>it()</code>, placeholders → automatic logging. Devs and testers contribute to the same repo.'
};
MODERN_NOTES['4-6'] = {
  title: 'Page Object Model + data-testid kill brittle tests',
  year: '2026',
  content: 'The "avoid screen-dependent steps" rule has a modern name: <strong>Page Object Model (POM)</strong>. Each page is a JS/Python class with stable methods (e.g., <code>loginPage.submit()</code>), so when the UI changes you update one file, not 200 tests. Best-practice marker: <strong><code>data-testid="submit-btn"</code></strong> attributes — invisible to users, immune to CSS changes. Cypress, Playwright, Testing Library all encourage data-testid over CSS selectors. Result: tests survive design overhauls.'
};
MODERN_NOTES['4-7'] = {
  title: 'BDD reframes Expected vs Actual as Given/When/Then',
  year: '2026',
  content: 'Modern BDD format makes the 3-cause investigation natural:<br>• <strong>Given</strong> a logged-in librarian (setup) → if this fails, it\'s usually #1 (test design) or #3 (auth bug)<br>• <strong>When</strong> I click Issue (action)<br>• <strong>Then</strong> book status = "Issued" (expected) → if fails, likely #3 (defect) or #2 (ambiguous spec)<br>Tools (Cucumber, SpecFlow) auto-generate skeletons from Given/When/Then in plain English. Business stakeholders can READ the tests.'
};
MODERN_NOTES['4-8'] = {
  title: 'Bathtub flattens in DevOps: continuous testing curve',
  year: '2026',
  content: 'The classic bathtub (plan early, execute late) assumes <strong>phase-based</strong> development. In CI/CD + DevOps, the curve flattens: testing activity is constant from day 1. <strong>DORA metrics</strong> (DevOps Research and Assessment) show elite teams test on EVERY commit. The new shape is more like a plateau: ~80% testing activity sustained from week 1 to production, then continuous in production (canary, A/B, monitoring). Bathtub still applies to enterprise + regulated projects (banking, medical, aerospace).'
};
MODERN_NOTES['4-9'] = {
  title: 'Modern gates: DoR/DoD, ephemeral envs, T-shirt estimation',
  year: '2026',
  content: 'These "advanced" criteria all have modern Agile equivalents. <strong>Entry/Exit Criteria → Definition of Ready (DoR) / Definition of Done (DoD)</strong> in Scrum — written on the team\'s wall, applied to every story. <strong>4 environments → ephemeral environments</strong> spun up per PR (Vercel Preview, GitHub Codespaces, Render PR envs). <strong>Estimation</strong> evolved: pure person-days only for fixed-bid contracts; Agile teams use <strong>T-shirt sizing (S/M/L/XL)</strong> + <strong>3-point estimation</strong> (best/likely/worst) + story points. Suspension criteria become <strong>CI/CD gating rules</strong> — pipeline stops automatically if smoke tests fail.'
};
MODERN_NOTES['4-10'] = {
  title: 'ISO/IEC/IEEE 29119: the 5-part modern standard',
  year: '2024',
  content: 'The current standard supersedes IEEE 829-1998. It\'s a <strong>5-part series</strong>: Part 1 (Concepts &amp; Definitions), Part 2 (Test Processes), Part 3 (Test Documentation), Part 4 (Test Techniques), Part 5 (Keyword-Driven Testing). 2022 update added <strong>AI testing</strong> coverage. Adoption: mandatory for ISO-9001-certified shops, common in EU/Asia, lighter in US Agile shops. Practical impact: when applying for ISTQB Advanced, expect 29119 references in exam questions.'
};
MODERN_NOTES['4-11'] = {
  title: 'IEEE 829\'s 8 docs → Jira / Notion / Confluence pages',
  year: '2026',
  content: 'In modern shops the 8 docs (and the 19 sections of an IEEE 829-style plan) rarely live as separate Word files. They\'re distributed across tools: <strong>Test Plan + Test Design Spec</strong> → Confluence page or Notion doc · <strong>Test Case Spec + Procedure</strong> → TestRail / Zephyr / Xray entries linked to Jira stories · <strong>Test Log</strong> → CI/CD output (GitHub Actions, GitLab CI) · <strong>Test Incident Report</strong> → Jira bug tickets · <strong>Test Summary Report</strong> → release notes + dashboard (Datadog, Grafana). The 8 documents didn\'t die — they got distributed and automated.'
};
MODERN_NOTES['4-12'] = {
  title: 'HSBC 2017 + UK Post Office Horizon: same lesson, decades apart',
  year: '2024',
  content: 'HSBC\'s 2017 outage is one of MANY banking IT failures: <strong>TSB UK (2018)</strong> botched data migration, £330M loss, CEO resigned. <strong>UK Post Office Horizon (1999-2024)</strong> — buggy accounting software wrongly prosecuted 900+ subpostmasters, multiple suicides, biggest miscarriage of justice in UK history. All preventable with the 10 test plan items — especially #7 (production-mirror environment) + #8 (performance + integration testing). Test planning is not bureaucracy. It saves lives, careers, and billions.'
};
